import{_ as e,o as d,c as r,ag as a}from"./chunks/framework.DXGyWiRo.js";const l="/images/lekt5802.jpg",i="/images/lekt5803.jpg",s="/images/lekt5806.jpg",n="/images/lekt5804.jpg",o="/images/lekt5805.jpg",h="/images/lekt5807.jpg",u="/images/lekt5801.jpg",b="/images/lekt5808.jpg",_=JSON.parse('{"title":"Lektion 58","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion58.md","filePath":"lektionen/lektion58.md"}'),p={name:"lektionen/lektion58.md"};function c(k,t,m,q,g,f){return d(),r("div",null,[...t[0]||(t[0]=[a('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-58" tabindex="-1">Lektion 58 <a class="header-anchor" href="#lektion-58" aria-label="Permalink to &quot;Lektion 58&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>58.1. Die Primärendungen des Dual (द्विवचनम्)</li><li>58.2. Der Dual thematischer Präsensklassen: Indikativ Präsens (लट्) <ul><li>58.2.1. Erste Präsensklasse (भ्वादिगणः)</li><li>58.2.2. Vierte Präsensklasse (दिवादिगणः)</li><li>58.2.3. Sechste Präsensklasse (तुदादिगणः)</li><li>58.2.4. Zehnte Präsensklasse (चुरादिगणः) und Kausative (णिजन्त)</li></ul></li><li>58.3. Der Dual des einfachen Futurs (ऌत्) <ul><li>58.3.1. अनिट्</li><li>58.3.2. सेट्</li></ul></li><li>58.4. Der Dual Passiv (Suffix -यक्)</li><li>58.5. Der Dual athematischer Präsensklassen: Indikativ Präsens (लट्) <ul><li>58.5.1. Zweite Präsensklasse (अदादिगणः)</li><li>58.5.2. Dritte Präsensklasse (जुहोत्यादिगणः)</li><li>58.5.3. Fünfte Präsensklasse (स्वादिगणः)</li><li>58.5.4. Achte Präsensklasse (तनादिगणः)</li><li>58.5.5. Siebte Präsensklasse (रुधादिगणः)</li><li>58.5.6. Neunte Präsensklasse (क्र्यादिगणः)</li></ul></li><li>58.6. Aorist 5: iṣ-Aorist</li><li>58.7. Übung</li></ul><h2 id="_58-1-die-primarendungen-des-dual-द्विवचनम्" tabindex="-1">58.1. Die Primärendungen des Dual (द्विवचनम्) <a class="header-anchor" href="#_58-1-die-primarendungen-des-dual-द्विवचनम्" aria-label="Permalink to &quot;58.1. Die Primärendungen des Dual (द्विवचनम्)&quot;">​</a></h2><table><tbody><tr><td></td><th>**परस्मैपदम्**</th><th colspan="2">आत्मनेपदम्</th></tr><tr><td></td><th></th><th>thematisch</th><th>athematisch</th></tr><tr><td>**1. तृतीयः**</td><td>-vas</td><td colspan="2">-vahe</td></tr><tr><td>**2. मध्यमः**</td><td>-thas</td><td>-īthe</td><td>-āthe</td></tr><tr><td>**3. प्रथमः**</td><td>-tas</td><td>-īte</td><td>-āte</td></tr></tbody></table><h2 id="_58-2-der-dual-thematischer-prasensklassen-indikativ-prasens-लट्" tabindex="-1">58.2. Der Dual thematischer Präsensklassen: Indikativ Präsens (लट्) <a class="header-anchor" href="#_58-2-der-dual-thematischer-prasensklassen-indikativ-prasens-लट्" aria-label="Permalink to &quot;58.2. Der Dual thematischer Präsensklassen: Indikativ Präsens (लट्)&quot;">​</a></h2><p>Vor -vas und -vahe wird der Themavokal -a- durch -ā- ersetzt.</p><h3 id="_58-2-1-erste-prasensklasse-भ्वादिगणः" tabindex="-1">58.2.1. Erste Präsensklasse (भ्वादिगणः) <a class="header-anchor" href="#_58-2-1-erste-prasensklasse-भ्वादिगणः" aria-label="Permalink to &quot;58.2.1. Erste Präsensklasse (भ्वादिगणः)&quot;">​</a></h3><p>भू 1P &quot;werden, sein&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>भवावस्</td><td></td></tr><tr><td>&quot;wir beide werden&quot;</td><td>&lt;भवावहे&gt;</td><td></td></tr><tr><td>2. मध्यमः</td><td>भवथस्</td><td></td></tr><tr><td>&quot;ihr beide werdet</td><td>&lt;भवेथे&gt;</td><td></td></tr><tr><td>bhav-a + īthe</td><td></td><td></td></tr><tr><td>3. प्रथमः</td><td>भवतस्</td><td></td></tr><tr><td>&quot;sie beide werden&quot;</td><td>&lt;भवेते&gt;</td><td></td></tr></tbody></table></blockquote><h3 id="_58-2-2-vierte-prasensklasse-दिवादिगणः" tabindex="-1">58.2.2. Vierte Präsensklasse (दिवादिगणः) <a class="header-anchor" href="#_58-2-2-vierte-prasensklasse-दिवादिगणः" aria-label="Permalink to &quot;58.2.2. Vierte Präsensklasse (दिवादिगणः)&quot;">​</a></h3><p>नृत् 4P &quot;tanzen&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>नृत्यावस्</td><td>नृत्यावहे</td></tr><tr><td>2. मध्यमः</td><td>नृत्यथस्</td><td>नृत्येथे</td></tr><tr><td>3. प्रथमः</td><td>नृत्यतस्</td><td>नृत्येते्</td></tr></tbody></table><p><img src="'+l+'" alt=""><br> Abb.: नृत्यतः<br> ओडिसी<br> [Bildquelle: Iqbal Saggu. -- <a href="http://www.flickr.com/photos/iqbalsaggu/964447408/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/iqbalsaggu/964447408/</a>. -- Zugriff am 2009-03-02. -- <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung)]</p></blockquote><h3 id="_58-2-3-sechste-prasensklasse-तुदादिगणः" tabindex="-1">58.2.3. Sechste Präsensklasse (तुदादिगणः) <a class="header-anchor" href="#_58-2-3-sechste-prasensklasse-तुदादिगणः" aria-label="Permalink to &quot;58.2.3. Sechste Präsensklasse (तुदादिगणः)&quot;">​</a></h3><p>तुद् 6U &quot;stoßen, schlagen&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>तुदावस्</td><td>तुदावहे</td></tr><tr><td>2. मध्यमः</td><td>तुदथस्</td><td>तुदेथे</td></tr><tr><td>3. प्रथमः</td><td>तुदतस्</td><td>तुदेते</td></tr></tbody></table></blockquote><h3 id="_58-2-4-zehnte-prasensklasse-चुरादिगणः-und-kausative-णिजन्त" tabindex="-1">58.2.4. Zehnte Präsensklasse (चुरादिगणः) und Kausative (णिजन्त) <a class="header-anchor" href="#_58-2-4-zehnte-prasensklasse-चुरादिगणः-und-kausative-णिजन्त" aria-label="Permalink to &quot;58.2.4. Zehnte Präsensklasse (चुरादिगणः) und Kausative (णिजन्त)&quot;">​</a></h3><p>चुर् 10U &quot;stehlen&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>चोरयावस्</td><td>चोरयावहे</td></tr><tr><td>2. मध्यमः</td><td>चोरयथस्</td><td>चोरयेथे</td></tr><tr><td>3. प्रथमः</td><td>चोरयतस्</td><td>चोरयेते</td></tr></tbody></table></blockquote><p><img src="'+i+'" alt=""><br> Abb.: वानरौ रथाद्भाण्डानि चोरयतः<br> Bandipur National Park -- ಬಂಡಿಪುರ ಅಭಯಾರಣ್ಯ</p><p>[Bildquelle: mattlogelin. -- <a href="http://www.flickr.com/photos/mattlogelin/362253669/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/mattlogelin/362253669/</a>. -- Zugriff am 2009-03-02. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung)]</p><h2 id="_58-3-der-dual-des-einfachen-futurs-ऌत्" tabindex="-1">58.3. Der Dual des einfachen Futurs (ऌत्) <a class="header-anchor" href="#_58-3-der-dual-des-einfachen-futurs-ऌत्" aria-label="Permalink to &quot;58.3. Der Dual des einfachen Futurs (ऌत्)&quot;">​</a></h2><h3 id="_58-3-1-अनिट्" tabindex="-1">58.3.1. अनिट् <a class="header-anchor" href="#_58-3-1-अनिट्" aria-label="Permalink to &quot;58.3.1. अनिट्&quot;">​</a></h3><p>दा 3U &quot;geben&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>दास्यावस्</td><td>दास्यावहे</td></tr><tr><td>2. मध्यमः</td><td>दास्यथस्</td><td>दास्येथे</td></tr><tr><td>3. प्रथमः</td><td>दास्यतस्</td><td>दास्येते</td></tr></tbody></table></blockquote><h3 id="_58-3-2-सेट्" tabindex="-1">58.3.2. सेट् <a class="header-anchor" href="#_58-3-2-सेट्" aria-label="Permalink to &quot;58.3.2. सेट्&quot;">​</a></h3><p>भू 1P &quot;werden, sein&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>भविष्यावस्</td><td>भविष्यावहे</td></tr><tr><td>2. मध्यमः</td><td>भविष्यथस्</td><td>भविष्येथे</td></tr><tr><td>3. प्रथमः</td><td>भविष्यतस्</td><td>भविष्येते</td></tr></tbody></table></blockquote><h2 id="_58-4-der-dual-passiv-suffix-यक्" tabindex="-1">58.4. Der Dual Passiv (Suffix -यक्) <a class="header-anchor" href="#_58-4-der-dual-passiv-suffix-यक्" aria-label="Permalink to &quot;58.4. Der Dual Passiv (Suffix -यक्)&quot;">​</a></h2><p>तुद् 6U &quot;stoßen, schlagen&quot;</p><blockquote><table tabindex="0"><thead><tr><th>1. तृतीयः</th><th>तुद्यवाहे</th></tr></thead><tbody><tr><td>2. मध्यमः</td><td>तुद्येथे</td></tr><tr><td>3. प्रथमः</td><td>तुद्येते</td></tr></tbody></table></blockquote><h2 id="_58-5-der-dual-athematischer-prasensklassen-indikativ-prasens-लट्" tabindex="-1">58.5. Der Dual athematischer Präsensklassen: Indikativ Präsens (लट्) <a class="header-anchor" href="#_58-5-der-dual-athematischer-prasensklassen-indikativ-prasens-लट्" aria-label="Permalink to &quot;58.5. Der Dual athematischer Präsensklassen: Indikativ Präsens (लट्)&quot;">​</a></h2><h3 id="_58-5-1-zweite-prasensklasse-अदादिगणः" tabindex="-1">58.5.1. Zweite Präsensklasse (अदादिगणः) <a class="header-anchor" href="#_58-5-1-zweite-prasensklasse-अदादिगणः" aria-label="Permalink to &quot;58.5.1. Zweite Präsensklasse (अदादिगणः)&quot;">​</a></h3><p>द्विष् 2U &quot;hassen&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>द्विष्वस्</td><td>द्विष्वहे</td></tr><tr><td>2. मध्यमः</td><td>द्विष्ठस्</td><td>द्विषाथे</td></tr><tr><td>3. प्रथमः</td><td>द्विष्टस्</td><td>द्विषाते</td></tr></tbody></table></blockquote><p>दुह् 2U &quot;melken&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>दुह्वस्</td><td>दुह्वहे</td></tr><tr><td>2. मध्यमः</td><td>दुग्धस्</td><td>दुहाथे</td></tr><tr><td>3. प्रथमः</td><td>दुग्धस्</td><td>दुहाते</td></tr></tbody></table></blockquote><p>इ 2P &quot;gehen&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>इवस्</td></tr><tr><td>2. मध्यमः</td><td>इथस्</td></tr><tr><td>3. प्रथमः</td><td>इतस्</td></tr></tbody></table></blockquote><p><img src="'+s+'" alt=""><br> Abb.: उष्ट्रौ मरावितः<br> [Bildquelle: stewils. -- <a href="http://www.flickr.com/photos/stewils/2231579675/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/stewils/2231579675/</a>. --  Zugriff am 2009-03-02. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine Kommerzielle Nutzung, keine Bearbeitung)]</p><p>इ + अधि 2Ā &quot;studieren&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>अधीवहे</td></tr><tr><td>2. मध्यमः</td><td>अधीयाथे</td></tr><tr><td>3. प्रथमः</td><td>अधीयते</td></tr></tbody></table></blockquote><p><img src="'+n+'" alt=""><br> Abb.: कन्ये अधीयते</p><p>[Bildquelle: One Laptop per Child. -- <a href="http://www.flickr.com/photos/olpc/3080618518/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/olpc/3080618518/</a>. -- Zugriff am 2009-03-02. -- <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung)]</p><p>हन् 2P &quot;erschlagen&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>हन्वस्</td></tr><tr><td>2. मध्यमः</td><td>हथस्</td></tr><tr><td>*hn-thas</td><td></td></tr><tr><td>3. प्रथमः</td><td>हतस्</td></tr></tbody></table></blockquote><p>अस् 2P &quot;sein&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>स्वस्</td></tr><tr><td>s-vas</td><td></td></tr><tr><td>2. मध्यमः</td><td>स्थस्</td></tr><tr><td>3. प्रथमः</td><td>स्तस्</td></tr></tbody></table></blockquote><p><img src="'+o+'" alt=""><br> Abb.: भगिन्यौ स्वः</p><p>[Bildquelle: saibotregeel. -- <a href="http://www.flickr.com/photos/saibotregeel/332951412/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/saibotregeel/332951412/</a>. -- Zugriff am 2009-03-02. -- <a href="http://creativecommons.org/licenses/by-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine Bearbeitung)]</p><h3 id="_58-5-2-dritte-prasensklasse-जुहोत्यादिगणः" tabindex="-1">58.5.2. Dritte Präsensklasse (जुहोत्यादिगणः) <a class="header-anchor" href="#_58-5-2-dritte-prasensklasse-जुहोत्यादिगणः" aria-label="Permalink to &quot;58.5.2. Dritte Präsensklasse (जुहोत्यादिगणः)&quot;">​</a></h3><p>हु 3P &quot;ins Opferfeuer gießen&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>जुहुवस्</td><td>&lt;जुहुवहे&gt;</td></tr><tr><td>2. मध्यमः</td><td>जुहुथस्</td><td>&lt;जुह्वाथे&gt;</td></tr><tr><td>3. प्रथमः</td><td>जुहुतस्</td><td>&lt;जुह्वाते&gt;</td></tr></tbody></table></blockquote><p>धा 3U &quot;setzen, legen, stellen&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>दध्वस्</td><td>दध्वहे</td></tr><tr><td>2. मध्यमः</td><td>धत्थस्</td><td>दधाथे</td></tr><tr><td>3. प्रथमः</td><td>धत्तस्</td><td>दधाते</td></tr></tbody></table></blockquote><h3 id="_58-5-3-funfte-prasensklasse-स्वादिगणः" tabindex="-1">58.5.3. Fünfte Präsensklasse (स्वादिगणः) <a class="header-anchor" href="#_58-5-3-funfte-prasensklasse-स्वादिगणः" aria-label="Permalink to &quot;58.5.3. Fünfte Präsensklasse (स्वादिगणः)&quot;">​</a></h3><p>सु 5U &quot;auspressen&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>सुनुवस् / सुन्वस्</td><td>सुनुवहे / सुन्वहे</td></tr><tr><td>2. मध्यमः</td><td>सुनुथस्</td><td>सुन्वाथे</td></tr><tr><td>3. प्रथमः</td><td>सुनुतस्</td><td>सुन्वाते</td></tr></tbody></table><p><img src="'+h+'" alt=""><br> Abb.: शर्कराम्बु सुनुतः<br> पुणेनगरे</p><p>[Bildquelle: FredMikeRudy. -- <a href="http://www.flickr.com/photos/fredmikerudy/2090687162/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/fredmikerudy/2090687162/</a>. -- Zugriff am 2009-03-02. -- <a href="http://creativecommons.org/licenses/by-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine Bearbeitung)]</p></blockquote><h3 id="_58-5-4-achte-prasensklasse-तनादिगणः" tabindex="-1">58.5.4. Achte Präsensklasse (तनादिगणः) <a class="header-anchor" href="#_58-5-4-achte-prasensklasse-तनादिगणः" aria-label="Permalink to &quot;58.5.4. Achte Präsensklasse (तनादिगणः)&quot;">​</a></h3><p>तन् 8U &quot;aufspannen&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>तनुवस् / तन्वस्</td><td>तनुवहे / तन्वहे</td></tr><tr><td>2. मध्यमः</td><td>तनुथस्</td><td>तन्वाथे</td></tr><tr><td>3. प्रथमः</td><td>तनुतस्</td><td>तन्वाते</td></tr></tbody></table></blockquote><p>कृ 8U &quot;tun, machen&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>कुर्वस्</td><td>कुर्वहे</td></tr><tr><td>2. मध्यमः</td><td>कुरुथस्</td><td>कुर्वाथे</td></tr><tr><td>3. प्रथमः</td><td>कुरुतस्</td><td>कुर्वाते</td></tr></tbody></table></blockquote><h3 id="_58-5-5-siebte-prasensklasse-रुधादिगणः" tabindex="-1">58.5.5. Siebte Präsensklasse (रुधादिगणः) <a class="header-anchor" href="#_58-5-5-siebte-prasensklasse-रुधादिगणः" aria-label="Permalink to &quot;58.5.5. Siebte Präsensklasse (रुधादिगणः)&quot;">​</a></h3><p>रुध् 7U &quot;stoppen&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>रुन्ध्वस्</td><td>रुन्ध्वहे</td></tr><tr><td>2. मध्यमः</td><td>रुन्द्धस्</td><td>रुन्धाथे</td></tr><tr><td>3. प्रथमः</td><td>रुन्द्धस्</td><td>रुन्धाते</td></tr></tbody></table></blockquote><p>युज् 7U &quot;anschirren&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>युञ्ज्वस्</td><td>युञ्ज्वहे</td></tr><tr><td>2. मध्यमः</td><td>युङ्क्थस्</td><td>युञ्जाथे</td></tr><tr><td>3. प्रथमः</td><td>युङ्क्तस्</td><td>युञ्जाते</td></tr></tbody></table></blockquote><h3 id="_58-5-6-neunte-prasensklasse-क्र्यादिगणः" tabindex="-1">58.5.6. Neunte Präsensklasse (क्र्यादिगणः) <a class="header-anchor" href="#_58-5-6-neunte-prasensklasse-क्र्यादिगणः" aria-label="Permalink to &quot;58.5.6. Neunte Präsensklasse (क्र्यादिगणः)&quot;">​</a></h3><p>क्री 9U &quot;kaufen&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>क्रीणीवस्</td><td>क्रीणीवहे</td></tr><tr><td>2. मध्यमः</td><td>क्रीणीथस्</td><td>क्रीणाथे</td></tr><tr><td>krī-ṇ-āthe</td><td></td><td></td></tr><tr><td>3. प्रथमः</td><td>क्रीणीतस्</td><td>क्रीणाते</td></tr></tbody></table><p><img src="'+u+'" alt=""><br> Abb.: स्त्रियौ शाकं क्रीणाते<br> [Bildquelle: Prato9x. -- <a href="http://www.flickr.com/photos/55163494@N00/262793331/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/55163494@N00/262793331/</a>. -- Zugriff am 2009-03-02. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p></blockquote><h2 id="_58-6-aorist-5-is-aorist" tabindex="-1">58.6. Aorist 5: iṣ-Aorist <a class="header-anchor" href="#_58-6-aorist-5-is-aorist" aria-label="Permalink to &quot;58.6. Aorist 5: iṣ-Aorist&quot;">​</a></h2><p>Der iṣ-Aorist wird von allen seṭ-Wurzeln gebildet, für die nicht ausdrücklich ausschließlich eine andere Form des Aorist gelehrt wird.</p><p>Bildung:</p><p>Augment + Wurzel + i + s + athematische Sekundärendung</p><p>!!! Die 2.sg.P bzw. 3.sg.P gehen auf -īs bzw. -īt aus !!! (Dies ist entstanden aus einer Übertragung des Imperfekts von Wurzeln des Typs अब्रवीत्; es sind also eigentlich Wurzelaorist-Formen).</p><p>Stammbildungssuffix + Endungen  des iṣ-Aorist lauten also:</p><table><tbody><tr><td></td><th colspan="2">परस्मैपदम्</th><th colspan="2">आत्मनेपदम्</th></tr><tr><td></td><th>एकवचनम्</th><th>बहुवचनम्</th><th>एकवचनम्</th><th>बहुवचनम्</th></tr><tr><td>**1. तृतीयः**</td><td>**-iṣam**</td><td>**-iṣma**</td><td>**-iṣi**</td><td>**-iṣmahi**</td></tr><tr><td>**2. द्वितीयः**</td><td>**-īs**</td><td>**-iṣṭa**</td><td>**-iṣṭhās**</td><td>**-idhvam /<br>-iḍhvam<br>**(wahlweise nach -h oder Halbvokal)</td></tr><tr><td>**3. प्रथमः**</td><td>**-īt**</td><td>**-iṣur**</td><td>**-iṣṭa**</td><td>**-iṣata**</td></tr></tbody></table><p>Form der Wurzel:</p><ul><li><p>Wurzeln mit kurzem Vokal vor einfachem Konsonanten: Hochstufe im P und Ā<br> Beispiele:<br> बुध् 1U: 1.sg.P अबोधिषम्<br> कॢप् 1Ā: 1.sg.Ā अकल्पिषि</p></li><li><p>Wurzeln mit auslautendem Vokal:</p><ul><li>P: Dehnstufe</li><li>Ā: Hochstufe</li></ul><p>Beispiele:<br> पू 9U: 1.sg.P अपाविषम् ; 1. sg.Ā अपविषि</p></li><li><p>Wurzeln auf -ar., -al sowie वद् 1P &quot;sagen&quot;, व्रज् 1P &quot;weggehen&quot;: P: Dehnstufe<br> Beispiele:<br> चर् 1P: 1.sg.P अचारिषम्<br> वद् 1P: 1.sg.P अवादिषम्</p></li><li><p>Andere Wurzeln der Form (Kons.-)Kons.-a-Kons.: im P wahlweise Dehnstufe (gilt nicht für Wurzeln auf -h, -m, -y sowie einige weitere Wurzeln)<br> Beispiel:<br> तन् 8U: 1.sg.P अतनिषम् / अतानिषम्<br> aber:<br> क्रम् 1U: 1.sg.P अक्रमिषम्</p></li></ul><p>Paradigmen:</p><p>पू 9U &quot;reinigen&quot;</p><blockquote><table><tbody><tr><td></td><th colspan="2">परस्मैपदम्</th><th colspan="2">आत्मनेपदम्</th></tr><tr><td></td><th>एकवचनम्</th><th>बहुवचनम्</th><th>एकवचनम्</th><th>बहुवचनम्</th></tr><tr><td>**1. तृतीयः**</td><td>अपाविषम्</td><td>पाविष्म</td><td>अपविषि</td><td>अपविष्महि</td></tr><tr><td>**2. द्वितीयः**</td><td>अपावीस्</td><td>अपाविष्ट</td><td>अपविष्ठास्</td><td>अपविध्वम् /<br>अपविढ्वम्</td></tr><tr><td>**3. प्रथमः**</td><td>अपावीत्</td><td>अपाविषुर्</td><td>अपविष्ट</td><td>पविषत</td></tr></tbody></table></blockquote><p>बुध् 1U  &quot;erwachen, erkennen&quot;</p><blockquote><table><tbody><tr><td></td><th colspan="2">परस्मैपदम्</th></tr><tr><td></td><th>एकवचनम्</th><th>बहुवचनम्</th></tr><tr><td>**1. तृतीयः**</td><td>अबोधिषम्</td><td>अबोधिष्म</td></tr><tr><td>**2. द्वितीयः**</td><td>अबोधीस्</td><td>अबोधिष्ट</td></tr><tr><td>**3. प्रथमः**</td><td>अबोधीत्</td><td>अबोधिषुर्</td></tr></tbody></table></blockquote><p>कॢप् 1Ā &quot;passend sein&quot;</p><blockquote><table><tbody><tr><td></td><th colspan="2">आत्मनेपदम्</th></tr><tr><td></td><th>एकवचनम्</th><th>बहुवचनम्</th></tr><tr><td>**1. तृतीयः**</td><td>अकल्पिषि</td><td>अकल्पिष्महि</td></tr><tr><td>**2. द्वितीयः**</td><td>अकल्पिष्ठास्</td><td>अकल्पिध्वम्</td></tr><tr><td>**3. प्रथमः**</td><td>अकल्पिष्ट</td><td>अकल्पिषत</td></tr></tbody></table></blockquote><p>Besonderheiten:</p><ol><li><p>Bei einigen Wurzeln kann der Bindevokal -i- im आत्मनेपद durch -ī- ersetzt werden. Nach ग्रह् 9U &quot;ergreifen&quot; muss diese Ersetzung im P und Ā erfolgen:<br> अग्रहीषम् , अग्रहीषि</p></li><li><p>Wurzeln der 8. Präsensklasse auf -n (oder -ṇ) können in der 2.3.sg.Ā tiefstufig sein:<br> तन् 8U: 2.sg.Ā अतनिष्ठास् / अतथस् (Wurzelaorist) ; 3. sg. Ā अतनिष्ट / अतत</p></li><li><p>दीप् 4Ā, जन् 4Ā u.a. können statt der 3.sg. Ā auch die Form des Passivaorists annehmen:<br> अदीपिष्ट / अदीपि ; अजनिष्ट / अजनि</p></li><li><p>विज् 7P hat keinen Ablaut:<br> अविजीत्</p></li></ol><p><img src="'+b+'" alt=""><br> Abb.: दीपः श्रीकृष्णाय श्रीगनेशाय चादीपिष्ट / चादीपि ॥</p><h2 id="_58-7-ubung" tabindex="-1">58.7. Übung <a class="header-anchor" href="#_58-7-ubung" aria-label="Permalink to &quot;58.7. Übung&quot;">​</a></h2><p>A) Bestimmen und übersetzen Sie ohne Hilfsmittel folgende Formen und bilden Sie die entsprechenden Formen des i-Aorist:</p><ol><li>औहे</li><li>जाग्रति</li><li>जीर्यन्ति</li><li>आनर्च</li><li>खादामः</li><li>नेद</li><li>आश्नीत</li><li>पुनते</li><li>अशेरत</li><li>इयेषिथ</li><li>आर्च्छत्</li><li>अर्हन्ति</li><li>ऊदुः</li><li>इन्त्से</li><li>आध्वे</li><li>कल्पे</li><li>आनीत्</li><li>ऐक्षध्वम्</li><li>अचेतः</li></ol><p>B) Übersetzen und bestimmen Sie folgende Formen:</p><ol><li>अनेढ्वम्</li><li>एनयोः</li><li>अष्टौ</li><li>चक्रम</li><li>ना</li><li>अत्तः</li><li>अधृत</li><li>ईहेरन्</li><li>अधिजगे</li><li>जग्म</li><li>अघ्रात्</li><li>अद्राक्ष्म</li><li>अस्थाः</li><li>अधमः</li><li>आनर्ध</li><li>पथोः</li><li>जेता</li><li>श्वा</li><li>स्वः</li><li>यदृच्छया</li><li>अकार्षम्</li><li>क्रीणीथः</li><li>क्रीणीथ</li><li>जानानि</li><li>भोः</li><li>अजैष्त</li><li>पुरा</li><li>देवा</li><li>गन्धी</li><li>ईय</li><li>नाना</li><li>देह</li><li>अतत</li><li>आप्स्यावः</li><li>अतौत्त</li><li>इमे</li><li>इतः</li><li>दद</li><li>अञ्ज्वः</li></ol>',96)])])}const w=e(p,[["render",c]]);export{_ as __pageData,w as default};
